SET standard_conforming_strings = OFF;
CREATE SCHEMA "public";
DROP TABLE IF EXISTS "public"."h3_milan" CASCADE;
BEGIN;
CREATE TABLE "public"."h3_milan" ( "ogc_fid" SERIAL, CONSTRAINT "h3_milan_pk" PRIMARY KEY ("ogc_fid") );
SELECT AddGeometryColumn('public','h3_milan','geom',4326,'POLYGON',2);
CREATE INDEX "h3_milan_geom_geom_idx" ON "public"."h3_milan" USING GIST ("geom");
ALTER TABLE "public"."h3_milan" ADD COLUMN "fid" NUMERIC(20,0);
ALTER TABLE "public"."h3_milan" ADD COLUMN "h3_id" VARCHAR;
COMMIT;
